$current = App\Models\ExamSetting::current(); if(!$current) { echo "No current ExamSetting found"; } else { $cycle = $current->current_cycle; echo "ExamSetting: id=" . $current->id . ", is_open=" . $current->is_open . ", current_cycle=" . $cycle . PHP_EOL; echo "In-progress results: " . App\Models\Result::where("cycle", $cycle)->whereNotNull("started_at")->whereNull("submitted_at")->count() . PHP_EOL; echo "In-progress exam_sessions: " . App\Models\ExamSession::where("cycle", $cycle)->count() . PHP_EOL; }
